args.ReplacementContent:
return (
  <AnimatePresence>
    {isOpen && (
      <motion.div
        initial={{ opacity: 0, backdropFilter: 'blur(0px)' }}
        animate={{ opacity: 1, backdropFilter: 'blur(30px)' }}
        exit={{ opacity: 0, backdropFilter: 'blur(0px)' }}
        transition={{ duration: 0.5 }}
        className="fixed inset-0 z-[100] bg-black/90 overflow-y-auto"
      >
        <div className="absolute top-8 right-8">
          <button
            onClick={onClose}
            className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-colors backdrop-blur-md"
          >
            <X size={24} />
          </button>
        </div>

        <div className="max-w-5xl mx-auto px-6 pt-32 pb-20">
          <div className="relative">
            <SearchIcon size={40} className="absolute left-0 top-1/2 -translate-y-1/2 text-white/40" />
            <input
              ref={inputRef}
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Explorer notre collection..."
              className="w-full bg-transparent border-b border-white/20 focus:border-white text-4xl md:text-6xl heading-font text-white placeholder:text-white/30 pl-16 md:pl-20 pb-6 outline-none transition-colors"
            />
          </div>

          <div className="mt-16">
            {isLoading && (
              <div className="text-[14px] text-white/50 animate-pulse">Recherche dans les archives...</div>
            )}

            {!isLoading && query.length >= 2 && results.length === 0 && (
              <div className="text-[18px] text-white/70">Aucune fragrance trouvée pour "{query}".</div>
            )}

            {!isLoading && results.length > 0 && (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-x-10 gap-y-12">
                {results.map((product) => (
                  <Link
                    key={product.id}
                    href={`/product/${product.slug}`}
                    onClick={onClose}
                    className="group flex items-center gap-6"
                  >
                    <div className="relative w-28 h-32 bg-white/5 rounded-xl overflow-hidden flex-shrink-0">
                      {product.images[0] && (
                        <Image
                          src={product.images[0]}
                          alt={product.name}
                          fill
                          className="object-cover group-hover:scale-110 transition-transform duration-700 opacity-90 group-hover:opacity-100"
                        />
                      )}
                    </div>
                    <div>
                      <div className="text-[10px] font-bold tracking-[0.3em] uppercase text-[#38bdf8] mb-2">
                        {product.brand}
                      </div>
                      <h3 className="heading-font text-2xl text-white group-hover:text-[#38bdf8] transition-colors line-clamp-2 leading-tight">
                        {product.name}
                      </h3>
                      <div className="text-[14px] font-light text-white/70 mt-3">
                        {product.price} MAD
                      </div>
                    </div>
                  </Link>
                ))}
              </div>
            )}

            {/* Suggestions when empty */}
            {!query && (
              <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.2 }}
                className="animate-fade-in"
              >
                <span className="text-[10px] font-bold tracking-[0.3em] uppercase text-white/40 mb-6 block">
                  Suggestions populaires
                </span>
                <div className="flex flex-wrap gap-4">
                  {['Baccarat Rouge', 'Armani', 'My Way', 'Tom Ford', 'YSL Libre'].map((tag) => (
                    <button
                      key={tag}
                      onClick={() => setQuery(tag)}
                      className="px-6 py-3 bg-white/5 hover:bg-white/10 border border-white/10 text-white text-[13px] rounded-full transition-all duration-300 hover:scale-105"
                    >
                      {tag}
                    </button>
                  ))}
                </div>
              </motion.div>
            )}
          </div>
        </div>
      </motion.div>
    )}
  </AnimatePresence>
);

